'use client'; import Image from 'next/image'; import dynamic from 'next/dynamic'; import {motion} from 'framer-motion'; import {ArrowUpRight,MapPin,Check,Send} from 'lucide-react'; import {Reveal} from './Reveal'; import {Bottle} from './Bottle'; import {PouringEffect} from './PouringEffect'; import {company,distribution} from '@/data/company'; import {products} from '@/data/products'; import {timeline} from '@/data/timeline';
const ProductScene=dynamic(()=>import('./three/ProductScene'),{ssr:false,loading:()=> <div className="absolute inset-0 grid place-items-center text-xs uppercase tracking-[.25em] text-[#d8ad55]/60">Memuat produk</div>});
const Button=({children,href='#produk',secondary=false}:{children:React.ReactNode,href?:string,secondary?:boolean})=><a href={href} className={`inline-flex min-h-12 items-center gap-2 rounded-full px-6 py-3 text-sm font-bold transition hover:-translate-y-1 ${secondary?'border border-white/30 text-white hover:border-[#d2a84a] hover:text-[#d2a84a]':'bg-[#d2a84a] text-[#4e0e0e] hover:bg-white'}`}>{children}<ArrowUpRight size={16}/></a>;
export function Hero(){return <section id="beranda" className="hero-contrast noise relative isolate min-h-[92vh] overflow-hidden bg-[#f6ecdd] px-5 pb-16 pt-32 text-[#1c1210] md:px-12 md:pb-20 md:pt-40"><div className="pointer-events-none absolute -right-40 top-0 h-[620px] w-[620px] rounded-full bg-[#8f1d1d]/20 blur-3xl"/><div className="pointer-events-none absolute -left-40 bottom-0 h-80 w-80 rounded-full bg-[#d2a84a]/20 blur-3xl"/><div className="relative mx-auto grid max-w-[1280px] items-center gap-10 lg:grid-cols-[.94fr_1.06fr] lg:gap-14"><div className="hero-copy relative z-10 max-w-2xl"><p className="hero-in mb-6 flex items-center gap-3 text-[11px] font-bold uppercase tracking-[.3em] text-[#851b1b]"><span className="h-px w-10 bg-[#d2a84a]"/>Warisan rasa dari Singkawang</p><h1 className="hero-in hero-delay-1 max-w-3xl text-[clamp(3.25rem,7vw,6.8rem)] leading-[.9] tracking-[-.045em]">Cita rasa <em className="text-[#b67822]">legendaris</em><br/><span className="text-[#4e0e0e]">dalam setiap tetes.</span></h1><p className="hero-in hero-delay-2 mt-8 max-w-lg text-base leading-7 text-[#553c32] md:text-lg">{company.shortDescription} Kecap manis pilihan untuk hidangan keluarga dan usaha kuliner yang ingin meninggalkan rasa.</p><div className="hero-in hero-delay-3 mt-9 flex flex-wrap gap-3"><Button>Lihat Produk</Button><Button href="#kontak" secondary>Jadi Mitra</Button></div><div className="hero-in hero-delay-3 mt-10 flex flex-wrap gap-x-6 gap-y-3 text-[10px] font-bold uppercase tracking-[.18em] text-[#6d4f42]"><span className="flex items-center gap-2"><span className="h-1.5 w-1.5 rounded-full bg-[#b67822]"/>Sejak 1965</span><span className="flex items-center gap-2"><span className="h-1.5 w-1.5 rounded-full bg-[#b67822]"/>Dibuat di Singkawang</span></div></div><div className="hero-product relative flex min-h-[430px] items-center justify-center rounded-[40px] bg-[radial-gradient(circle_at_52%_42%,rgba(210,168,74,.34),transparent_25%),linear-gradient(145deg,#8f1d1d,#3b0808)] shadow-[0_28px_80px_rgba(78,14,14,.25)] md:min-h-[570px] md:rounded-[56px]"><div className="absolute inset-3 rounded-[34px] border border-white/10 md:inset-5 md:rounded-[48px]"/><div className="orbit absolute h-64 w-64 rounded-full border border-[#d8ad55]/50 md:h-[27rem] md:w-[27rem]"/><div className="absolute h-44 w-44 rounded-full bg-[#d8ad55]/25 blur-2xl md:h-64 md:w-64"/><motion.div className="hero-bottle absolute inset-0" animate={{rotateZ:[0,0,14,14,0,0]}} transition={{duration:7,repeat:Infinity,ease:[.4,0,.2,1],times:[0,.25,.38,.62,.78,1]}}><ProductScene/><div className="pointer-events-none absolute inset-0 opacity-25"><Bottle/></div><PouringEffect/></motion.div><div className="absolute bottom-5 left-5 flex items-center gap-3 text-[10px] uppercase tracking-[.18em] text-white/60 md:bottom-7 md:left-7"><span className="grid h-8 w-8 place-items-center rounded-full border border-[#d2a84a]/60 text-[#d2a84a]">↗</span><span>Geser untuk<br/>menjelajah</span></div><span className="absolute bottom-5 right-5 max-w-[130px] text-right text-[10px] uppercase tracking-[.18em] text-white/50 md:bottom-7 md:right-7">Elang Dua<br/>Kecap Manis</span></div></div><div className="absolute bottom-7 left-5 text-[10px] uppercase tracking-[.3em] text-[#851b1b]/60 md:left-12">Rasa yang tinggal di ingatan</div></section>}
export function About(){return <section id="tentang" className="px-5 py-24 md:px-12 md:py-36"><div className="mx-auto grid max-w-[1280px] gap-14 lg:grid-cols-2 lg:items-center"><Reveal><p className="text-sm font-bold uppercase tracking-[.25em] text-[#8f1d1d]">01 Ã¢â‚¬â€ Tentang Elang Dua</p><h2 className="mt-5 text-5xl leading-tight md:text-6xl">Dibuat dengan niat baik, <em className="text-[#8f1d1d]">dinikmati</em> sepenuh hati.</h2><p className="mt-7 max-w-xl leading-8 text-[#6b6b6b]">{company.description}</p></Reveal><Reveal delay={.1} className="relative"><div className="rounded-[32px] bg-[#8f1d1d] p-8 text-white md:p-12"><span className="block text-[8rem] font-serif leading-none text-[#d2a84a]">{company.founded}</span><p className="max-w-xs text-lg">Tahun perjalanan menemani cita rasa Indonesia.</p><div className="mt-12 flex items-center gap-3 text-sm text-white/70"><MapPin size={18} className="text-[#d2a84a]"/>{company.city}</div></div></Reveal></div></section>}
export function Products(){return <section id="produk" className="bg-white px-5 py-24 md:px-12 md:py-32"><div className="mx-auto max-w-[1280px]"><Reveal><p className="text-sm font-bold uppercase tracking-[.25em] text-[#8f1d1d]">02 Ã¢â‚¬â€ Produk unggulan</p><div className="mt-4 flex flex-wrap items-end justify-between gap-5"><h2 className="text-5xl md:text-6xl">Untuk setiap <em className="text-[#8f1d1d]">momen.</em></h2><p className="max-w-xs text-sm leading-6 text-[#6b6b6b]">Pilihan rasa untuk kebutuhan dapur sehari-hari.</p></div></Reveal><div className="mt-14 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">{products.map((p,i)=><Reveal key={p.name} delay={i*.06}><motion.article whileHover={{y:-6}} className="group overflow-hidden rounded-3xl border border-[#171717]/10 bg-[#f6f0e4] p-5"><div className={`relative flex h-60 items-center justify-center overflow-hidden rounded-2xl ${p.tone==='light'?'bg-[#e9dfcc]':p.tone==='amber'?'bg-[#a66b21]':p.tone==='red'?'bg-[#8f1d1d]':'bg-[#4e0e0e]'}`}><div className="scale-[.45] transition duration-500 group-hover:scale-[.5]"><Bottle/></div><span className="absolute left-4 top-4 rounded-full bg-white/15 px-3 py-1 text-[10px] uppercase tracking-widest text-white">Produk</span></div><h3 className="mt-5 text-2xl">{p.name}</h3><p className="mt-2 min-h-12 text-sm leading-6 text-[#6b6b6b]">{p.description}</p><p className="mt-4 text-xs text-[#8f1d1d]">{p.variant}</p></motion.article></Reveal>)}</div></div></section>}
export function Advantages(){return <section className="bg-[#171717] px-5 py-24 text-white md:px-12"><div className="mx-auto max-w-[1280px]"><Reveal><p className="text-sm font-bold uppercase tracking-[.25em] text-[#d2a84a]">03 Ã¢â‚¬â€ Mengapa Elang Dua</p><h2 className="mt-5 max-w-2xl text-5xl md:text-6xl">Rasa yang <em className="text-[#d2a84a]">konsisten</em>, cerita yang terus tumbuh.</h2></Reveal><div className="mt-16 grid gap-8 border-t border-white/15 pt-8 md:grid-cols-2 lg:grid-cols-5">{['Rasa konsisten','Pengalaman sejak 1965','Standar kualitas','Untuk rumah & usaha','Distribusi berkembang'].map((x,i)=><Reveal key={x} delay={i*.05}><div className="border-b border-white/15 pb-8 lg:border-b-0"><span className="text-[#d2a84a]">0{i+1}</span><Check className="my-8 text-[#d2a84a]" size={22}/><h3 className="text-xl">{x}</h3></div></Reveal>)}</div></div></section>}
export function History(){return <section id="sejarah" className="px-5 py-24 md:px-12 md:py-32"><div className="mx-auto max-w-[1280px]"><Reveal><p className="text-sm font-bold uppercase tracking-[.25em] text-[#8f1d1d]">04 Ã¢â‚¬â€ Sejarah</p><h2 className="mt-5 text-5xl md:text-6xl">Satu perjalanan,<br/><em className="text-[#8f1d1d]">banyak cerita.</em></h2></Reveal><div className="mt-16 border-l-2 border-[#d2a84a] pl-7 md:ml-20 md:pl-12">{timeline.map((t,i)=><Reveal key={t.title} delay={i*.08} className="relative mb-12 last:mb-0"><span className="absolute -left-[38px] top-1 h-4 w-4 rounded-full border-4 border-[#f6f0e4] bg-[#8f1d1d] md:-left-[59px]"/><p className="text-sm font-bold text-[#8f1d1d]">{t.year}</p><h3 className="mt-2 text-2xl">{t.title}</h3><p className="mt-2 max-w-xl leading-7 text-[#6b6b6b]">{t.text}</p></Reveal>)}</div></div></section>}
export function Distribution(){return <section className="bg-[#d2a84a] px-5 py-24 md:px-12"><div className="mx-auto grid max-w-[1280px] gap-12 lg:grid-cols-2 lg:items-center"><Reveal><p className="text-sm font-bold uppercase tracking-[.25em] text-[#4e0e0e]">05 Ã¢â‚¬â€ Area distribusi</p><h2 className="mt-5 text-5xl text-[#4e0e0e] md:text-6xl">Dari Singkawang,<br/><em>melangkah lebih jauh.</em></h2><p className="mt-6 max-w-lg leading-7 text-[#4e0e0e]/75">Kami terus bertumbuh bersama konsumen dan mitra di berbagai wilayah. Ingin menjadi bagian dari perjalanan ini?</p><Button href="#kontak">Menjadi distributor</Button></Reveal><Reveal className="rounded-[32px] bg-[#4e0e0e] p-8 text-white md:p-12"><p className="text-sm uppercase tracking-widest text-[#d2a84a]">Jangkauan kami</p>{distribution.map((d,i)=><div key={d} className="flex items-center justify-between border-b border-white/15 py-5 text-lg"><span>{d}</span><span className="text-[#d2a84a]">0{i+1}</span></div>)}</Reveal></div></section>}
export function Location(){return <section id="lokasi" className="px-5 py-24 md:px-12 md:py-32"><div className="mx-auto grid max-w-[1280px] gap-12 lg:grid-cols-[.8fr_1.2fr]"><Reveal><p className="text-sm font-bold uppercase tracking-[.25em] text-[#8f1d1d]">06 Ã¢â‚¬â€ Lokasi</p><h2 className="mt-5 text-5xl md:text-6xl">Mari <em className="text-[#8f1d1d]">berkunjung.</em></h2><div className="mt-10 space-y-6 text-[#6b6b6b]"><p className="flex gap-3"><MapPin className="shrink-0 text-[#8f1d1d]"/> {company.address}</p><p><strong className="text-[#171717]">Jam operasional</strong><br/>{company.hours}</p></div>{company.mapsUrl&&<Button href={company.mapsUrl}>Buka Google Maps</Button>}</Reveal><Reveal className="grid min-h-[320px] place-items-center rounded-[32px] bg-[#e6d8c0] text-center"><div><MapPin size={42} className="mx-auto text-[#8f1d1d]"/><p className="mt-4 font-serif text-3xl text-[#4e0e0e]">Singkawang</p><p className="mt-2 text-sm text-[#6b6b6b]">TODO: Tambahkan preview peta atau embed resmi.</p></div></Reveal></div></section>}
export function Contact(){return <section id="kontak" className="bg-[#4e0e0e] px-5 py-24 text-white md:px-12 md:py-32"><div className="mx-auto grid max-w-[1280px] gap-14 lg:grid-cols-2"><Reveal><p className="text-sm font-bold uppercase tracking-[.25em] text-[#d2a84a]">07 Ã¢â‚¬â€ Hubungi kami</p><h2 className="mt-5 text-5xl md:text-6xl">Mari mulai <em className="text-[#d2a84a]">percakapan.</em></h2><p className="mt-7 max-w-md leading-7 text-white/60">Punya pertanyaan tentang produk, distribusi, atau peluang kerja sama? Sampaikan kepada kami.</p><div className="mt-10 flex gap-4 text-white/70"><a aria-label="Instagram" href={company.instagram||'#'}><span>Instagram</span></a><a aria-label="Facebook" href={company.facebook||'#'}><span>Facebook</span></a></div></Reveal><Reveal><form className="space-y-4" action={`https://wa.me/${company.whatsapp}`}><input required placeholder="Nama" className="w-full rounded-2xl border border-white/15 bg-white/10 px-5 py-4 outline-none placeholder:text-white/40 focus:border-[#d2a84a]"/><input type="text" placeholder="Nomor WhatsApp atau Email" className="w-full rounded-2xl border border-white/15 bg-white/10 px-5 py-4 outline-none placeholder:text-white/40 focus:border-[#d2a84a]"/><input placeholder="Subjek" className="w-full rounded-2xl border border-white/15 bg-white/10 px-5 py-4 outline-none placeholder:text-white/40 focus:border-[#d2a84a]"/><textarea required placeholder="Pesan" rows={5} className="w-full resize-none rounded-2xl border border-white/15 bg-white/10 px-5 py-4 outline-none placeholder:text-white/40 focus:border-[#d2a84a]"/><button className="inline-flex min-h-12 items-center gap-2 rounded-full bg-[#d2a84a] px-6 py-3 font-bold text-[#4e0e0e]">Kirim pesan <Send size={16}/></button></form></Reveal></div></section>}
export function Footer(){return <footer className="relative overflow-hidden bg-[#2b0707] px-5 py-10 text-white md:px-12"><div className="pointer-events-none absolute -bottom-7 right-4 select-none font-serif text-[clamp(5rem,16vw,14rem)] font-bold leading-none text-white/[.04]">ELANG DUA</div><div className="relative mx-auto flex max-w-[1280px] flex-col justify-between gap-6 md:flex-row md:items-end"><div><div className="relative h-[52px] w-[170px]"><Image src="/images/logo/elang-dua-logo.png" alt="Elang Dua" fill sizes="170px" className="object-contain object-left"/></div><p className="mt-2 text-sm text-white/45">{company.shortDescription}</p></div><p className="text-sm text-white/45">© {new Date().getFullYear()} Elang Dua. Seluruh hak cipta dilindungi.</p></div></footer>}
